class Solution:
    def checkAlmostEquivalent(self, word1, word2):
        freq = [0] * 26
        for ch in word1:
            freq[ord(ch) - 97] += 1
        for ch in word2:
            freq[ord(ch) - 97] -= 1
        return all(abs(x) <= 3 for x in freq)

