from collections import Counter


class Solution:
    def checkAlmostEquivalent(self, word1, word2):
        c1, c2 = Counter(word1), Counter(word2)
        for ch in set(c1) | set(c2):
            if abs(c1[ch] - c2[ch]) > 3:
                return False
        return True

